const input = ($node["When Chat Message Received"].json.chatInput || '').trim();
let raw = input.replace(/^(do\s+osint\s+on|do\s+osint|osint\s+on|osint|research|analyze|lookup\s+on|lookup|find|on)\s+/i, '').trim();

let targetName = '';
let company = '';

const fromPattern = /^(.+?)\s+(?:from|at)\s+(.+)$/i;
const m = raw.match(fromPattern);

if (m) {
  targetName = m[1].trim();
  company = m[2].trim();
} else if (raw.includes(',')) {
  const parts = raw.split(',');
  targetName = parts[0].trim();
  company = parts.slice(1).join(',').trim();
} else {
  targetName = raw;
  company = '';
}

let domainSearch = company || targetName;
let companyClean = domainSearch.toLowerCase().replace(/\s+/g, '');
if (!companyClean.includes('.')) {
  companyClean += '.com';
}

return [{ json: { targetName, company, companyClean, originalInput: input } }];

const emails = Array.isArray($json.data?.emails) ? $json.data.emails : [];
const cleanEmails = emails.map(e => {
  let res = { email: e.value };
  let fullName = (e.first_name || '') + ' ' + (e.last_name || '');
  if (fullName.trim()) res.name = fullName.trim();
  if (e.position) res.position = e.position;
  if (e.department) res.department = e.department;
  return res;
});
return [{ json: { emails: cleanEmails, pattern: $json.data?.pattern || '', org: $json.data?.organization || '' } }];

const getSafe = (nodeName, prop) => {
  try {
    return $node[nodeName].json[prop];
  } catch (e) {
    return prop === 'pattern' || prop === 'org' ? '' : [];
  }
};

const linkedin = getSafe('Parse LinkedIn', 'linkedin');
const social = getSafe('Parse Social Media', 'social');
const emails = getSafe('Parse Hunter Data', 'emails');
const pattern = getSafe('Parse Hunter Data', 'pattern');
const org = getSafe('Parse Hunter Data', 'org');

return [{ json: { linkedin, social, emails, pattern, org } }];

const raw = $json.choices && $json.choices[0] && $json.choices[0].message ? $json.choices[0].message.content : 'No analysis available.';
const target = $node['Parse Target Input'].json.targetName || 'Unknown';
const company = $node['Parse Target Input'].json.company || 'Unknown';
const ts = new Date().toISOString().replace('T', ' ').slice(0, 19) + ' UTC';
const divider = '═'.repeat(43);
const line = '─'.repeat(43);
const report = divider + '
🔍  OSINT INTELLIGENCE REPORT
' + divider + '

📋 Target: ' + target + '
🏢 Organization: ' + company + '
🕐 Generated: ' + ts + '
🔒 Classification: FOR AUTHORIZED USE ONLY

' + line + '

' + raw + '

' + line + '
📌 Report generated via n8n OSINT Pipeline
⚠️  This report is for authorized security assessment purposes only.
' + divider;
return [{ json: { formattedReport: report } }];
